export async function up(pgm) {
  pgm.sql(`
    INSERT INTO provider_models
      (provider_id, model_key, display_name, status, capabilities, settings, created_by)
    SELECT
      p.id,
      left(COALESCE(model_parameter.plain_value, p.slug || '-default'), 240),
      left(COALESCE(model_parameter.plain_value, p.name || ' Default'), 240),
      CASE WHEN p.status = 'connected' THEN 'active'::provider_model_status ELSE 'inactive'::provider_model_status END,
      '{"autoGenerated":true}'::jsonb,
      COALESCE(safe_parameters.settings, '{}'::jsonb),
      p.created_by
    FROM ai_providers p
    LEFT JOIN LATERAL (
      SELECT x.plain_value
      FROM ai_provider_parameters x
      WHERE x.provider_id = p.id
        AND x.plain_value IS NOT NULL
        AND lower(x.key) ~ '(^|[_.-])model([_.-]?id)?$'
      ORDER BY CASE WHEN lower(x.key) ~ 'model[_.-]?id$' THEN 0 ELSE 1 END, x.created_at
      LIMIT 1
    ) model_parameter ON true
    LEFT JOIN LATERAL (
      SELECT jsonb_object_agg(x.key, x.plain_value) AS settings
      FROM ai_provider_parameters x
      WHERE x.provider_id = p.id
        AND x.plain_value IS NOT NULL
        AND lower(x.key) !~ '(api[_.-]?key|token|secret|password|credential|auth)'
    ) safe_parameters ON true
    WHERE p.deleted_at IS NULL
      AND NOT EXISTS (
        SELECT 1 FROM provider_models m
        WHERE m.provider_id = p.id AND m.deleted_at IS NULL
      );
  `);
}

